func formatNextDueForInput(t pgtype.Timestamptz) string {
	if !t.Valid || t.Time.IsZero() {
		return time.Now().Format("2006-01-02T15:04")
	}
	return t.Time.Format("2006-01-02T15:04")
}

func intervalAmount(h pgtype.Int4) string {
	if !h.Valid {
		return "1"
	}
	if h.Int32 >= 24 && h.Int32%24 == 0 {
		return fmt.Sprintf("%d", h.Int32/24)
	}
	return fmt.Sprintf("%d", h.Int32)
}

func intervalUnit(h pgtype.Int4) string {
	if !h.Valid {
		return "days"
	}
	if h.Int32 >= 24 && h.Int32%24 == 0 {
		return "days"
	}
	return "hours"
}

func templateJSON(t sql.ScheduleTemplate) string {
	intervalType := "once"
	intervalAmount := "1"
	intervalUnit_ := "days"
	if t.MorningEvening {
		intervalType = "morning_evening"
	} else if t.IntervalHours.Valid {
		intervalType = "repeat"
		h := t.IntervalHours.Int32
		if h >= 24 && h%24 == 0 {
			intervalAmount = fmt.Sprintf("%d", h/24)
		} else {
			intervalAmount = fmt.Sprintf("%d", h)
			intervalUnit_ = "hours"
		}
	}
	endType := "none"
	endCount := ""
	if t.RemainingCount.Valid {
		endType = "count"
		endCount = fmt.Sprintf("%d", t.RemainingCount.Int32)
	}
	return fmt.Sprintf(`{"description":%q,"intervalType":%q,"intervalAmount":%q,"intervalUnit":%q,"endType":%q,"endCount":%q}`,
		t.Description, intervalType, intervalAmount, intervalUnit_, endType, endCount)
}

func taskManagementToggleValue(on bool) string {
	if on {
		return "false"
	}
	return "true"
}

func canSnooze(intervalHours pgtype.Int4, morningEvening bool) bool {
	if morningEvening {
		return false
	}
	if !intervalHours.Valid {
		return true
	}
	return intervalHours.Int32 >= 24
}

func hasStandardTemplates(templates []sql.ScheduleTemplate) bool {
	for _, t := range templates {
		if t.Standard {
			return true
		}
	}
	return false
}

